// After Merge: input[0] = PDF Vector Extract, input[1] = PDF Vector Insights
const allInputs = $input.all();
const extractData = (allInputs[0]?.json?.data || allInputs[0]?.json) || {};
const insightsData = allInputs[1]?.json || {};
const insights = insightsData.markdown || insightsData.answer || '';

const fileName = $('New Chapter').item.json.name;
const fileId   = $('New Chapter').item.json.id;

const quotes    = (extractData.notableQuotesList   || '').split(';').filter(q => q.trim());
const actions   = (extractData.actionItemsList     || '').split(';').filter(a => a.trim());
const arguments_= (extractData.mainArgumentsList   || '').split(';').filter(a => a.trim());
const concepts  = (extractData.keyConceptsList     || '').split(',').filter(c => c.trim());
const questions = (extractData.discussionQuestionsList || '').split(';').filter(q => q.trim());

const actionList   = actions.map(a   => `→ ${a.trim()}`).join('\n')      || 'None';
const quoteList    = quotes.map(q    => `❝ ${q.trim()}`).join('\n\n')   || 'None';
const argumentList = arguments_.map((a,i) => `${i+1}. ${a.trim()}`).join('\n') || 'None';
const questionsList = questions.map((q,i) => `${i+1}. ${q.trim()}`).join('\n') || 'None';

return [{ json: {
  bookTitle:      extractData.bookTitle      || 'Unknown',
  authorName:     extractData.authorName     || 'N/A',
  author:         extractData.authorName     || 'N/A',
  chapterNumber:  extractData.chapterNumber  || 'N/A',
  chapterTitle:   extractData.chapterTitle   || 'N/A',
  pageRange:      extractData.pageRange      || 'N/A',
  mainThemesList: extractData.mainThemesList || 'N/A',
  themesList:     extractData.mainThemesList || 'N/A',
  keyConceptsList: extractData.keyConceptsList || 'N/A',
  mainArgumentsList: extractData.mainArgumentsList || 'N/A',
  notableQuotesList: extractData.notableQuotesList || 'N/A',
  actionItemsList:   extractData.actionItemsList   || 'N/A',
  chapterSummary:    extractData.chapterSummary    || 'N/A',
  mainTakeaway:   insights,
  aiInsights:     insights,
  argumentList,  argumentCount: arguments_.length,
  quoteList,     quoteCount:    quotes.length,
  actionList,    actionCount:   actions.length,
  conceptCount:  concepts.length,
  questionsList,
  fileName, fileId,
  processedAt: new Date().toISOString()
}}];

